            for (int x=0; x<m; x++) {
                for (int y=0; y<n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        list.add(new int[]{x,y});
                    }
                }
            }
        }
        teleport.add(list);
    }

    // Dijkstra's setup
    long[][][] dist = new long[m][n][k+1];
    for (int i=0; i<m; i++) {
        for (int j=0; j<n; j++) {
            for (int t=0; t<=k; t++) {
                dist[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dist[0][0][0] = 0;

    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
    pq.offer(new long[]{0, 0, 0, 0}); // cost, t, i, j

    while (!pq.isEmpty()) {
        long cost = pq.peek()[0];
        int t = pq.peek()[1];
        int i = pq.peek()[2];
        int j = pq.peek()[3];
        pq.poll();

        if (i == m-1 && j == n-1) {
            return cost;
        }

        // Check if current state is already processed with a lower cost
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Move right
        if (j+1 < n) {
            long newCost = cost + grid[i][j+1];
            if (newCost < dist[i][j+1][t]) {
                dist[i][j+1][t] = newCost;
                pq.offer(new long[]{newCost, t, i, j+1});
            }
        }

        // Move down
