public static long solve(long[][] grid, long k) {

    int m = grid.length;
    int n = grid[0].length;

    // Precompute teleport lists
    List<List<int[]>> teleportList = new ArrayList<>();
    for (int i = 0; i < m; i++) {
        List<int[]> list = new ArrayList<>();
        for (int j = 0; j < n; j++) {
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        list.add(new int[]{x, y});
                    }
                }
            }
        }
        teleportList.add(list);
    }

    // Dijkstra's algorithm
    long[][][] dist = new long[m][n][k+1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int t = 0; t <= k; t++) {
                dist[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dist[0][0][0] = 0;

    // Priority queue: (cost, teleports_used, i, j)
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    pq.offer(new long[]{0, 0, 0, 0});

    while (!pq.isEmpty()) {
        long currentCost = pq.peek()[0];
        int t = pq.peek()[1];
        int i = pq.peek()[2];
        int j = pq.peek()[3];
        pq.poll();

        // Check if we reached the destination
        if (i == m-1 && j == n-1) {
            return currentCost;
        }

        // Normal moves: right and down
        int[] directions = {0, 1, 1, 0}; // right, down
        for (int d = 0; d < 2; d++) {
            int ni = i + directions[d];
            int nj = j + directions[d];
            if (ni < m && nj < n) {
                long newCost = currentCost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    pq.offer(new long[]{newCost, t, ni, nj});
                }
            }
        }

        // Teleportation
        List<int[]> teleportCells = teleportList.get(i).get(j);
        for (int[] xy : teleportCells) {
            int x = xy[0];
            int y = xy[1];
            if (t < k) {
                long newT = t + 1;
                if (currentCost < dist[x][y][newT]) {
                    dist[x][y][newT] = currentCost;
                    pq.offer(new long[]{currentCost, newT, x, y});
                }
            }
        }
    }

    // If not found, return something? But the problem says it's always possible.
